output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT DISTINCT ?conflict ?label ?startDate WHERE {
  ?conflict wdt:P17 wd:Q96 ; wdt:P31 ?type ; rdfs:label ?label .
  VALUES ?type {
    wd:Q8465 wd:Q124734
  }
  FILTER(lang(?label) = "en")
  OPTIONAL {
    ?conflict wdt:P580 ?startDate
  }
}
ORDER BY ?startDate
LIMIT 10

args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?conflict ?label ?startDate
WHERE {
  ?conflict wdt:P17 wd:Q96 ;
            rdfs:label ?label .
  FILTER(lang(?label) = "en")
  {
    ?conflict wdt:P31 wd:Q8465 .  # instance of civil war
  }
  UNION
  {
    ?conflict wdt:P31 wd:Q124734 .  # instance of rebellion
  }
  OPTIONAL { ?conflict wdt:P580 ?startDate }
}
ORDER BY ?startDate
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?conflict ?label ?startDate
WHERE {
  ?conflict wdt:P17 wd:Q96 ;
            rdfs:label ?label .
  FILTER(lang(?label) = "en")
  FILTER REGEX(?label, "(?i)rebell?ion|uprising|civil war")
  OPTIONAL { ?conflict wdt:P580 ?startDate }
}
ORDER BY ?startDate
LIMIT 10

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT DISTINCT ?conflict ?label (YEAR(?startDate) AS ?startYear)
WHERE {
  ?conflict wdt:P17 wd:Q96 ;
            wdt:P31 ?type ;
            rdfs:label ?label .
  VALUES ?type { wd:Q8465 wd:Q124734 }
  FILTER(lang(?label) = "en")
  OPTIONAL { ?conflict wdt:P580 ?startDate }
  FILTER(BOUND(?startDate))
}
ORDER BY ?startDate
LIMIT 10

